// ============================================================
// DATOS DE EJEMPLO para test manual
// En producción, los datos vienen del Webhook
// ============================================================
return [{
  json: {
    proyecto: "Auditorio CC Buenavista",
    cliente: "JMD Salamanca",
    sala: "Salón de Actos",
    core_modelo: "Core 8 Flex",
    core_ip: "192.168.1.100",
    dispositivos: [
      {
        id: "proj1",
        tipo: "epson_projector",
        nombre: "Proyector Principal",
        ip: "192.168.1.101",
        puerto: 3629,
        descripcion: "EPSON EB-PU2010B"
      },
      {
        id: "video1",
        tipo: "roland_v80hd",
        nombre: "Mesa de Video",
        ip: "192.168.1.102",
        puerto: 8023,
        descripcion: "Roland V80HD"
      },
      {
        id: "lw_tx",
        tipo: "lightware_hdbaset",
        nombre: "Extensor HDMI TX",
        ip: "192.168.1.103",
        puerto: 6107,
        descripcion: "Lightware HDMI-TPS-TX86"
      },
      {
        id: "lw_rx",
        tipo: "lightware_hdbaset",
        nombre: "Extensor HDMI RX",
        ip: "192.168.1.110",
        puerto: 6107,
        descripcion: "Lightware HDMI-TPS-RX86"
      },
      {
        id: "audio1",
        tipo: "midas_m32",
        nombre: "Mesa de Audio M32",
        ip: "192.168.1.104",
        puerto: 10023,
        descripcion: "Midas M32 Live"
      },
      {
        id: "rf1",
        tipo: "shure_qlxd",
        nombre: "Receptor RF 1",
        ip: "192.168.1.105",
        puerto: 2202,
        descripcion: "Shure QLXD4E - Canal A"
      },
      {
        id: "rf2",
        tipo: "shure_qlxd",
        nombre: "Receptor RF 2",
        ip: "192.168.1.106",
        puerto: 2202,
        descripcion: "Shure QLXD4E - Canal B"
      },
      {
        id: "luz1",
        tipo: "chamsys_magicq",
        nombre: "Mesa de Iluminacion",
        ip: "192.168.1.107",
        puerto: 9000,
        descripcion: "Chamsys MagicQ MQ50"
      }
    ]
  }
}];

// ============================================================
// PREPARAR INPUT desde Webhook o Test
// ============================================================
const item = items[0].json;

// Si viene del webhook, el body está en item.body
const data = item.body || item;

const dispositivos = data.dispositivos || [];

// Validar que hay dispositivos
if (!dispositivos.length) {
  throw new Error('No se han proporcionado dispositivos. Incluye al menos un dispositivo en el array "dispositivos".');
}

// Validar campos requeridos de cada dispositivo
for (const d of dispositivos) {
  if (!d.tipo) throw new Error(`Dispositivo ${d.id || 'sin ID'}: falta campo "tipo"`);
  if (!d.nombre) throw new Error(`Dispositivo ${d.id || 'sin ID'}: falta campo "nombre"`);
  if (!d.ip) throw new Error(`Dispositivo ${d.id || 'sin ID'}: falta campo "ip"`);
}

return [{ json: {
  proyecto: data.proyecto || 'Proyecto Sin Nombre',
  cliente: data.cliente || 'Cliente',
  sala: data.sala || 'Sala Principal',
  core_modelo: data.core_modelo || 'Core 8 Flex',
  core_ip: data.core_ip || '192.168.1.100',
  dispositivos,
  fecha: new Date().toLocaleDateString('es-ES'),
  timestamp: new Date().toISOString()
}}];

// ============================================================
// GENERADOR DE LAYOUT UCI + NAMED COMPONENTS
// ============================================================
const input = items[0].json;
const dispositivos = input.dispositivos || [];
const scripts = input.scripts || [];

// Definicion de controles UCI por tipo de dispositivo
const UCI_CONTROLS = {
  epson_projector: [
    { nombre: 'Estado',     tipo: 'Text Feedback',   descripcion: 'Estado conexion TCP' },
    { nombre: 'Encendido',  tipo: 'Indicator',        descripcion: 'Indicador encendido/apagado' },
    { nombre: 'Encender',   tipo: 'Momentary Button', descripcion: 'Boton encender proyector' },
    { nombre: 'Apagar',     tipo: 'Momentary Button', descripcion: 'Boton apagar proyector' },
    { nombre: 'Entrada',    tipo: 'Combo Box',        descripcion: 'Selector entrada video (0=HDMI1, 1=HDMI2, 2=VGA)' },
    { nombre: 'AVMute',     tipo: 'Toggle Button',    descripcion: 'Apagar imagen (AV Mute)' },
    { nombre: 'Freeze',     tipo: 'Toggle Button',    descripcion: 'Congelar imagen' }
  ],
  roland_v80hd: [
    { nombre: 'Estado',      tipo: 'Text Feedback',   descripcion: 'Estado conexion TCP' },
    { nombre: 'Entrada PGM', tipo: 'Combo Box',        descripcion: 'Fuente en programa (0=HDMI1..5=IN6)' },
    { nombre: 'Entrada PVW', tipo: 'Combo Box',        descripcion: 'Fuente en preview' },
    { nombre: 'Fuente PGM',  tipo: 'Text Feedback',   descripcion: 'Fuente actual PGM' },
    { nombre: 'Fuente PVW',  tipo: 'Text Feedback',   descripcion: 'Fuente actual PVW' },
    { nombre: 'CUT',         tipo: 'Momentary Button', descripcion: 'Corte directo a PGM' },
    { nombre: 'AUTO',        tipo: 'Momentary Button', descripcion: 'Transicion automatica' }
  ],
  lightware_hdbaset: [
    { nombre: 'Estado',     tipo: 'Text Feedback',   descripcion: 'Estado conexion TCP' },
    { nombre: 'Senal',      tipo: 'Indicator',        descripcion: 'Presencia de senal HDMI' },
    { nombre: 'Resolucion', tipo: 'Text Feedback',   descripcion: 'Resolucion detectada' },
    { nombre: 'HDCP',       tipo: 'Text Feedback',   descripcion: 'Estado HDCP' },
    { nombre: 'Lock',       tipo: 'Toggle Button',    descripcion: 'Bloquear salida' }
  ],
  midas_m32: [
    { nombre: 'Master',     tipo: 'Fader',            descripcion: 'Fader master LR (0-1)' },
    { nombre: 'Mute Ch 1',  tipo: 'Toggle Button',    descripcion: 'Mute canal 1' },
    { nombre: 'Mute Ch 2',  tipo: 'Toggle Button',    descripcion: 'Mute canal 2' },
    { nombre: 'Escena',     tipo: 'Knob',             descripcion: 'Recall de escena (numero)' }
  ],
  shure_qlxd: [
    { nombre: 'Estado',      tipo: 'Text Feedback',   descripcion: 'Estado conexion / power' },
    { nombre: 'Bateria',     tipo: 'Level Meter',      descripcion: 'Nivel bateria 0-100%' },
    { nombre: 'RF',          tipo: 'Level Meter',      descripcion: 'Nivel RF 0-110' },
    { nombre: 'Audio',       tipo: 'Level Meter',      descripcion: 'Nivel audio' },
    { nombre: 'Mute',        tipo: 'Toggle Button',    descripcion: 'Mute del receptor' },
    { nombre: 'Alerta Bat',  tipo: 'Text Feedback',   descripcion: 'Alerta bateria baja' },
    { nombre: 'Nombre Canal',tipo: 'Text Feedback',   descripcion: 'Nombre del canal configurado' }
  ],
  chamsys_magicq: [
    { nombre: 'PB1 Go',    tipo: 'Momentary Button', descripcion: 'Playback 1 - Ejecutar' },
    { nombre: 'PB1 Stop',  tipo: 'Momentary Button', descripcion: 'Playback 1 - Parar' },
    { nombre: 'PB1 Nivel', tipo: 'Fader',            descripcion: 'Playback 1 - Nivel' },
    { nombre: 'PB2 Go',    tipo: 'Momentary Button', descripcion: 'Playback 2 - Ejecutar' },
    { nombre: 'PB2 Stop',  tipo: 'Momentary Button', descripcion: 'Playback 2 - Parar' },
    { nombre: 'PB2 Nivel', tipo: 'Fader',            descripcion: 'Playback 2 - Nivel' },
    { nombre: 'PB3 Go',    tipo: 'Momentary Button', descripcion: 'Playback 3 - Ejecutar' },
    { nombre: 'PB3 Stop',  tipo: 'Momentary Button', descripcion: 'Playback 3 - Parar' },
    { nombre: 'PB4 Go',    tipo: 'Momentary Button', descripcion: 'Playback 4 - Ejecutar' },
    { nombre: 'PB4 Stop',  tipo: 'Momentary Button', descripcion: 'Playback 4 - Parar' },
    { nombre: 'Blackout',  tipo: 'Toggle Button',    descripcion: 'Blackout general' }
  ],
  generic_tcp: [
    { nombre: 'Estado', tipo: 'Text Feedback',   descripcion: 'Estado conexion TCP' },
    { nombre: 'CMD 1',  tipo: 'Momentary Button', descripcion: 'Comando 1 (definir segun equipo)' },
    { nombre: 'CMD 2',  tipo: 'Momentary Button', descripcion: 'Comando 2 (definir segun equipo)' }
  ]
};

// Generar lista de Named Components
const namedComponents = [];
const uciLayout = [];

for (const d of dispositivos) {
  const tipo = d.tipo in UCI_CONTROLS ? d.tipo : 'generic_tcp';
  const controls = UCI_CONTROLS[tipo] || [];

  // Named Component para este dispositivo
  const nc = {
    nombre_componente: d.nombre,
    tipo_componente: 'Script',
    descripcion: `Control TCP: ${d.descripcion || d.tipo} - ${d.ip}:${d.puerto}`,
    script_file: `CTRL_${d.nombre.replace(/[^a-zA-Z0-9_]/g, '_')}.lua`,
    controls: controls.map(c => ({
      nombre_control: `${d.nombre} - ${c.nombre}`,
      tipo_uci: c.tipo,
      descripcion: c.descripcion
    }))
  };
  namedComponents.push(nc);

  // Seccion en UCI
  uciLayout.push({
    dispositivo: d.nombre,
    tipo: d.tipo,
    descripcion: d.descripcion,
    ip: d.ip,
    puerto: d.puerto,
    controles_uci: controls.map(c => `${d.nombre} - ${c.nombre}`),
    notas_implementacion: getImplementationNotes(d.tipo)
  });
}

function getImplementationNotes(tipo) {
  const notes = {
    epson_projector: 'Plugin alternativo disponible en QSC Plugin Store. ESC/VP.net requiere handshake inicial.',
    roland_v80hd: 'Verificar numero de puerto TCP en configuracion de red del V80HD. Ajustar comandos SVSW segun version de firmware.',
    lightware_hdbaset: 'LW3 Protocol. El Tx y Rx son unidades independientes con su propia IP. Verificar rutas /MEDIA/VIDEO segun modelo.',
    midas_m32: 'OSC/UDP. Activar OSC en M32: Setup > Remote > Enable OSC. Q-SYS necesita UdpSocket (v9.x+) o plugin.',
    shure_qlxd: 'SWP TCP. Activar control de red en Shure Wireless Workbench. Verificar que el receptor tiene IP fija asignada.',
    chamsys_magicq: 'OSC/UDP. En MagicQ: Setup > Network > OSC. Ajustar numeros de playback segun programacion de luz.',
    generic_tcp: 'Template generico. Revisar documentacion del fabricante para comandos especificos.'
  };
  return notes[tipo] || 'Consultar documentacion del fabricante.';
}

// Sugerencia de layout de paginas UCI
const uciPages = [
  {
    pagina: 1,
    nombre: 'Control General',
    descripcion: 'Vista rapida de todos los sistemas',
    dispositivos_mostrados: dispositivos.map(d => d.nombre)
  },
  {
    pagina: 2,
    nombre: 'Audio',
    descripcion: 'Control de mesa de audio y microfonia',
    dispositivos_mostrados: dispositivos.filter(d => ['midas_m32', 'shure_qlxd'].includes(d.tipo)).map(d => d.nombre)
  },
  {
    pagina: 3,
    nombre: 'Video',
    descripcion: 'Control de proyector y mesa de video',
    dispositivos_mostrados: dispositivos.filter(d => ['epson_projector', 'roland_v80hd', 'lightware_hdbaset'].includes(d.tipo)).map(d => d.nombre)
  },
  {
    pagina: 4,
    nombre: 'Iluminacion',
    descripcion: 'Control de mesa de luces',
    dispositivos_mostrados: dispositivos.filter(d => d.tipo === 'chamsys_magicq').map(d => d.nombre)
  }
].filter(p => p.dispositivos_mostrados.length > 0);

return [{ json: { ...input, named_components: namedComponents, uci_layout: uciLayout, uci_pages: uciPages } }];

// ============================================================
// ENSAMBLAR SALIDA FINAL
// HTML con toda la configuracion + JSON estructurado
// ============================================================
const input = items[0].json;
const { proyecto, cliente, sala, core_modelo, core_ip, dispositivos,
        scripts, named_components, uci_pages, uci_layout, fecha } = input;

// --- Tabla de IPs ---
const ipTableRows = dispositivos.map(d => `
  <tr>
    <td><strong>${d.nombre}</strong></td>
    <td>${d.descripcion || d.tipo}</td>
    <td><code>${d.ip}</code></td>
    <td>${d.puerto}</td>
    <td>${d.tipo}</td>
  </tr>`).join('');

// --- Scripts Lua ---
const scriptSections = scripts.map(s => `
  <div class="script-block">
    <div class="script-header">
      <span class="badge">${s.tipo}</span>
      <strong>${s.nombre}</strong> — <code>${s.filename}</code>
      ${s.warning ? `<span class="warning">⚠ ${s.warning}</span>` : ''}
    </div>
    <pre class="lua-code">${s.script.replace(/</g,'&lt;').replace(/>/g,'&gt;')}</pre>
  </div>`).join('');

// --- Named Components ---
const ncRows = named_components.map(nc => `
  <div class="nc-block">
    <h4>📦 Componente: <strong>${nc.nombre_componente}</strong></h4>
    <p>${nc.descripcion}</p>
    <p><em>Script:</em> <code>${nc.script_file}</code></p>
    <table>
      <thead><tr><th>Nombre Control</th><th>Tipo UCI</th><th>Descripcion</th></tr></thead>
      <tbody>
        ${nc.controls.map(c => `<tr><td><code>${c.nombre_control}</code></td><td>${c.tipo_uci}</td><td>${c.descripcion}</td></tr>`).join('')}
      </tbody>
    </table>
  </div>`).join('');

// --- Paginas UCI ---
const uciPagesHtml = uci_pages.map(p => `
  <div class="uci-page">
    <h4>Pagina ${p.pagina}: ${p.nombre}</h4>
    <p>${p.descripcion}</p>
    <ul>${p.dispositivos_mostrados.map(d => `<li>${d}</li>`).join('')}</ul>
  </div>`).join('');

// --- Notas de implementacion ---
const notasHtml = uci_layout.map(d => `
  <li><strong>${d.dispositivo}</strong> (${d.ip}:${d.puerto}): ${d.notas_implementacion}</li>`).join('');

// --- HTML final ---
const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<title>Q-SYS Config — ${proyecto}</title>
<style>
  body { font-family: 'Segoe UI', sans-serif; max-width: 1200px; margin: 0 auto; padding: 20px; color: #1a1a2e; background: #f5f5f5; }
  h1 { background: #1a1a2e; color: white; padding: 20px 30px; border-radius: 8px; }
  h1 span { color: #e94560; }
  h2 { border-left: 4px solid #e94560; padding-left: 12px; margin-top: 40px; }
  h3 { color: #1a1a2e; }
  .meta { background: white; padding: 16px; border-radius: 8px; display: grid; grid-template-columns: repeat(3,1fr); gap: 12px; box-shadow: 0 2px 8px rgba(0,0,0,.08); }
  .meta-item label { font-size: 11px; text-transform: uppercase; color: #999; display: block; }
  .meta-item strong { font-size: 16px; }
  table { width: 100%; border-collapse: collapse; background: white; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,.08); }
  th { background: #1a1a2e; color: white; padding: 10px 14px; text-align: left; font-size: 12px; }
  td { padding: 10px 14px; border-bottom: 1px solid #eee; font-size: 13px; }
  tr:hover td { background: #f0f0f0; }
  code { background: #eee; padding: 2px 6px; border-radius: 4px; font-family: monospace; font-size: 13px; }
  pre.lua-code { background: #0d1117; color: #c9d1d9; padding: 20px; border-radius: 8px; overflow-x: auto; font-size: 12px; line-height: 1.6; font-family: 'Consolas', 'Monaco', monospace; }
  .script-block { margin: 20px 0; border: 1px solid #ddd; border-radius: 8px; overflow: hidden; }
  .script-header { background: #1a1a2e; color: white; padding: 10px 16px; display: flex; align-items: center; gap: 10px; flex-wrap: wrap; }
  .badge { background: #e94560; padding: 2px 10px; border-radius: 12px; font-size: 11px; text-transform: uppercase; }
  .warning { background: #ff9800; color: black; padding: 2px 10px; border-radius: 12px; font-size: 11px; }
  .nc-block { background: white; padding: 16px; margin: 16px 0; border-radius: 8px; box-shadow: 0 2px 8px rgba(0,0,0,.08); }
  .nc-block h4 { margin: 0 0 8px; }
  .uci-page { background: white; padding: 14px 18px; margin: 10px 0; border-radius: 8px; border-left: 4px solid #e94560; }
  .step { background: white; padding: 16px; margin: 10px 0; border-radius: 8px; border-left: 4px solid #1a1a2e; }
  .step h4 { margin: 0 0 8px; color: #1a1a2e; }
  footer { text-align: center; color: #999; margin-top: 40px; font-size: 12px; padding: 20px; border-top: 1px solid #eee; }
</style>
</head>
<body>

<h1>🎛️ Q-SYS Configuration — <span>${proyecto}</span></h1>

<div class="meta">
  <div class="meta-item"><label>Cliente</label><strong>${cliente}</strong></div>
  <div class="meta-item"><label>Sala</label><strong>${sala}</strong></div>
  <div class="meta-item"><label>Core Q-SYS</label><strong>${core_modelo}</strong></div>
  <div class="meta-item"><label>IP del Core</label><strong><code>${core_ip}</code></strong></div>
  <div class="meta-item"><label>Equipos</label><strong>${dispositivos.length} dispositivos</strong></div>
  <div class="meta-item"><label>Generado</label><strong>${fecha}</strong></div>
</div>

<h2>📡 Tabla de Direccionamiento IP</h2>
<table>
  <thead><tr><th>Dispositivo</th><th>Modelo</th><th>IP</th><th>Puerto</th><th>Tipo</th></tr></thead>
  <tbody>
    <tr><td><strong>Core Q-SYS</strong></td><td>${core_modelo}</td><td><code>${core_ip}</code></td><td>—</td><td>qsys_core</td></tr>
    ${ipTableRows}
  </tbody>
</table>

<h2>🗂️ Paginas UCI — Estructura Sugerida para Tablet</h2>
${uciPagesHtml}
<p><em>Implementar en Q-SYS Designer > UCI > New Page. Asignar controles Named segun lista de componentes.</em></p>

<h2>📦 Named Components — Lista para Q-SYS Designer</h2>
<p>Crear un componente <strong>Script</strong> por cada dispositivo y asignar los Named Controls indicados:</p>
${ncRows}

<h2>📝 Scripts Lua — Copiar en Q-SYS Designer</h2>
<p>Para cada dispositivo: crear un componente <strong>Script</strong>, pegar el codigo y ajustar si es necesario.</p>
${scriptSections}

<h2>⚙️ Pasos de Implementacion en Q-SYS Designer</h2>
<div class="step"><h4>1. Abrir Q-SYS Designer y crear nuevo proyecto</h4><p>File > New Design. Seleccionar Core 8 Flex como procesador principal.</p></div>
<div class="step"><h4>2. Configurar red</h4><p>En el Core, asignar IP: <code>${core_ip}</code>. Verificar que todos los equipos son accesibles desde la misma subred.</p></div>
<div class="step"><h4>3. Crear Named Components (Script)</h4><p>Para cada dispositivo de la lista, arrastrar un componente <strong>Script</strong> al canvas. Nombrar exactamente como indica la columna "Nombre Componente".</p></div>
<div class="step"><h4>4. Pegar scripts Lua</h4><p>Doble clic en cada componente Script > pegar el codigo correspondiente. Los scripts ya tienen la IP y puerto correctos.</p></div>
<div class="step"><h4>5. Crear controles Named</h4><p>En cada Script Component > Pins > agregar los controles listados en la tabla de Named Components.</p></div>
<div class="step"><h4>6. Diseñar UCI</h4><p>Design > UCI > New Page. Arrastrar controles desde los Named Components a cada pagina segun la estructura sugerida.</p></div>
<div class="step"><h4>7. Desplegar y probar</h4><p>File > Deploy. En cada dispositivo verificar la conexion TCP/UDP y el estado de los controles.</p></div>

<h2>📌 Notas de Implementacion por Equipo</h2>
<ul>${notasHtml}</ul>

<footer>Generado automaticamente por Q-SYS Config Generator — Vitel SA &nbsp;|&nbsp; ${new Date().toLocaleString('es-ES')}</footer>
</body>
</html>`;

// JSON estructurado de la configuracion
const config_json = {
  proyecto, cliente, sala, core_modelo, core_ip, fecha,
  dispositivos: dispositivos.length,
  scripts: scripts.map(s => ({ id: s.id, nombre: s.nombre, filename: s.filename, tipo: s.tipo, ip: s.ip, puerto: s.puerto })),
  named_components: named_components.map(nc => nc.nombre_componente),
  uci_pages: uci_pages.map(p => p.nombre)
};

return [{ json: {
  success: true,
  proyecto,
  cliente,
  html_report: html,
  config_summary: config_json,
  scripts_raw: scripts,
  named_components_full: named_components,
  uci_structure: uci_pages,
  total_devices: dispositivos.length,
  generated_at: new Date().toISOString()
}}];
